list.query:
SELECT value, label FROM (
  SELECT '' AS value, '' AS label
  UNION ALL
  SELECT DISTINCT dbname AS value, dbname AS label FROM awr_load_profile
) AS t ORDER BY value;

SELECT value, label FROM (
  SELECT '' AS value, '' AS label
  UNION ALL
  SELECT DISTINCT instance AS value, instance AS label FROM awr_load_profile WHERE dbname = '$dbname'
) AS t ORDER BY value;

SELECT label FROM (
  SELECT '' AS label
  UNION ALL
  SELECT DISTINCT begin_snap::int || ' - ' || to_char(snap_time,'YYYY-MM-DD HH24:MI:SS') AS label FROM awr_load_profile WHERE dbname = '$dbname' AND instance = '$instance'
) AS t ORDER BY label NULLS FIRST;

SELECT label FROM (
  SELECT '' AS label
  UNION ALL
  SELECT DISTINCT begin_snap::int || ' - ' || to_char(snap_time,'YYYY-MM-DD HH24:MI:SS') AS label FROM awr_load_profile WHERE dbname = '$dbname' AND instance = '$instance'
) AS t ORDER BY label NULLS FIRST;
